import { useRef, useState, useCallback } from "react";
import type { ProviderFormat } from "../types/core";
import { parseSSEStream } from "../utils/parseSSE";

export interface UseCompletionOptions {
  /** API endpoint */
  api: string;
  /** Initial prompt (optional — can pass at call time) */
  initialPrompt?: string;
  /** Additional body params */
  body?: Record<string, unknown>;
  /** Headers */
  headers?: HeadersInit;
  /** Provider format for SSE parsing */
  providerFormat?: ProviderFormat;
  /** Callback on completion */
  onFinish?: (completion: string) => void;
  /** Callback on error */
  onError?: (error: Error) => void;
}

export interface UseCompletionReturn {
  /** Full completion text (streaming or final) */
  completion: string;
  /** Trigger a completion */
  complete: (prompt: string, overrideBody?: Record<string, unknown>) => Promise<void>;
  /** Abort in-flight completion */
  abort: () => void;
  /** True while streaming/loading */
  isLoading: boolean;
  /** Error state */
  error: Error | null;
  /** Reset completion to empty string */
  reset: () => void;
}

export function useCompletion(options: UseCompletionOptions): UseCompletionReturn {
  const [completion, setCompletion] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const abortControllerRef = useRef<AbortController | null>(null);
  const contentRef = useRef("");

  // Track latest options to avoid stale closures
  const optionsRef = useRef(options);
  optionsRef.current = options;

  const abort = useCallback(() => {
    abortControllerRef.current?.abort();
  }, []);

  const reset = useCallback(() => {
    contentRef.current = "";
    setCompletion("");
    setError(null);
    setIsLoading(false);
  }, []);

  const complete = useCallback(
    async (prompt: string, overrideBody?: Record<string, unknown>) => {
      // Abort any in-flight request (concurrent call protection)
      abortControllerRef.current?.abort();
      const controller = new AbortController();
      abortControllerRef.current = controller;

      contentRef.current = "";
      setCompletion("");
      setError(null);
      setIsLoading(true);

      const opts = optionsRef.current;

      try {
        const response = await fetch(opts.api, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            ...opts.headers,
          },
          body: JSON.stringify({
            ...opts.body,
            prompt,
            ...overrideBody,
          }),
          signal: controller.signal,
        });

        if (!response.ok) {
          let message = `HTTP ${response.status}`;
          try {
            const errBody = (await response.json()) as {
              error?: { message?: string };
            };
            message = errBody.error?.message ?? message;
          } catch {
            // ignore
          }
          throw new Error(message);
        }

        const contentType = response.headers.get("content-type") ?? "";
        const isSSE = contentType.includes("text/event-stream");

        if (isSSE) {
          // Stream SSE response
          const reader = response.body?.getReader();
          if (!reader) throw new Error("Response body is not readable");

          const decoder = new TextDecoder();
          const format = opts.providerFormat ?? "openai";

          while (true) {
            const { done, value } = await reader.read();
            if (done) break;

            const chunk = decoder.decode(value, { stream: true });
            for (const delta of parseSSEStream(chunk, format)) {
              contentRef.current += delta;
              setCompletion(contentRef.current);
            }
          }
        } else {
          // Non-streaming JSON response — extract text
          const data = (await response.json()) as {
            choices?: Array<{ message?: { content?: string } }>;
            content?: Array<{ text?: string }>;
          };
          const text =
            data.choices?.[0]?.message?.content ??
            data.content?.[0]?.text ??
            "";
          contentRef.current = text;
          setCompletion(text);
        }

        opts.onFinish?.(contentRef.current);
      } catch (err) {
        if (err instanceof Error && err.name === "AbortError") {
          return;
        }
        const finalError = err instanceof Error ? err : new Error(String(err));
        setError(finalError);
        opts.onError?.(finalError);
      } finally {
        setIsLoading(false);
      }
    },
    []
  );

  return { completion, complete, abort, isLoading, error, reset };
}

// Core types for @inferface/hooks
// ---------------------------------------------------------------------------

export type StreamTransport = (
  input: RequestInfo | URL,
  init?: RequestInit
) => Promise<Response>;

export type MessageRole = "user" | "assistant" | "system" | "tool";

// ---------------------------------------------------------------------------
// Rich Content / Content Parts
// ---------------------------------------------------------------------------

/** Data shape for an embedded chart */
export interface ChartData {
  type: "bar" | "line" | "pie" | "scatter" | string;
  labels?: string[];
  datasets: {
    label?: string;
    data: number[];
    [key: string]: unknown;
  }[];
  options?: Record<string, unknown>;
}

export type ContentPart =
  | { type: "text"; text: string }
  | { type: "image_url"; image_url: { url: string; alt?: string } }
  | { type: "chart"; data: ChartData }
  | { type: "custom"; component: string; props: unknown };

export interface Message {
  id: string;
  role: MessageRole;
  /**
   * String for plain-text messages; ContentPart[] for rich/multimodal content.
   * Hooks always return string during streaming accumulation.
   * Use `extractText(content)` to get a plain string in either case.
   */
  content: string | ContentPart[];
  createdAt?: Date;
  toolCallId?: string;
  toolCalls?: ToolCall[];
}

export interface ToolCall {
  id: string;
  type: "function";
  function: {
    name: string;
    arguments: string; // JSON string — stream accumulates this
  };
}

export interface ToolResult {
  toolCallId: string;
  result: unknown;
  error?: Error;
}

export type ProviderFormat = "openai" | "anthropic" | "custom";

/**
 * Extract a plain text string from Message.content regardless of form.
 * Concatenates all `text` parts for ContentPart[] content.
 */
export function extractText(content: string | ContentPart[]): string {
  if (typeof content === "string") return content;
  return content
    .filter((p): p is { type: "text"; text: string } => p.type === "text")
    .map((p) => p.text)
    .join("");
}

/**
 * Parse OpenAI SSE chunk.
 * Format: data: {"choices":[{"delta":{"content":"hello"},...}]}
 * Sentinel: data: [DONE]
 */
export function parseOpenAIChunk(raw: string): string | null {
  if (raw === "[DONE]") return null;
  try {
    const parsed = JSON.parse(raw) as {
      choices?: Array<{ delta?: { content?: string } }>;
    };
    return parsed.choices?.[0]?.delta?.content ?? null;
  } catch {
    return null;
  }
}

/**
 * Parse Anthropic SSE chunk.
 * Requires the event type from the preceding `event:` line.
 */
export function parseAnthropicChunk(raw: string, eventType?: string): string | null {
  if (eventType === "message_stop" || eventType === "message_delta") return null;
  try {
    const parsed = JSON.parse(raw) as {
      type?: string;
      delta?: { type?: string; text?: string };
    };
    if (parsed.type === "content_block_delta" && parsed.delta?.type === "text_delta") {
      return parsed.delta.text ?? null;
    }
    return null;
  } catch {
    return null;
  }
}

/**
 * Parse a raw SSE stream body into text deltas.
 * Handles both OpenAI and Anthropic formats.
 */
export function* parseSSEStream(
  chunk: string,
  format: "openai" | "anthropic" | "custom"
): Generator<string> {
  const lines = chunk.split("\n");
  let currentEvent: string | undefined;

  for (const line of lines) {
    if (line.startsWith("event:")) {
      currentEvent = line.slice(6).trim();
      continue;
    }
    if (line.startsWith("data:")) {
      const data = line.slice(5).trim();
      if (!data) continue;

      let text: string | null = null;
      if (format === "openai") {
        text = parseOpenAIChunk(data);
      } else if (format === "anthropic") {
        text = parseAnthropicChunk(data, currentEvent);
      }

      if (text !== null) {
        yield text;
      }
      currentEvent = undefined;
    }
  }
}
